external_knowledge:
- A "big heart" refers to vehicles with multiple models; 
- "not a one-hit wonder" means the model appears more than once in the database; 
- A "powerful engine" means the engine size is greater than 2.0 liters.

sql:
SELECT version_name, price
FROM vehicle_versions
WHERE vehicle_id = 3;

SELECT v.model_year, v.make, v.model
FROM vehicles v
WHERE v.horsepower = (
    SELECT MAX(horsepower)
    FROM vehicles
);

SELECT v.vehicle_id, v.make, v.model, ve.version_name, ve.price
FROM vehicles v
JOIN vehicle_versions ve ON v.vehicle_id = ve.vehicle_id;

SELECT DISTINCT users.user_name, users.email
FROM users
JOIN access_logs ON users.user_id = access_logs.user_id;
